class Relation:
    def __init__(self, name, attributes, tuples):
        self.name = name
        self.attributes = attributes  # List of attribute names
        self.tuples = tuples          # List of tuples (rows)

    def get_degree(self):
        """Returns number of attributes (degree)"""
        return len(self.attributes)

    def get_cardinality(self):
        """Returns number of tuples (cardinality)"""
        return len(self.tuples)

    def find_keys(self, pk_columns):
        """Identifies different types of keys"""
        # pk_columns is list of columns forming primary key
        super_keys = []
        # Generate all super keys containing PK
        for i in range(len(self.attributes)):
            combo = pk_columns.copy()
            for j in range(len(self.attributes)):
                if self.attributes[j] not in pk_columns:
                    combo.append(self.attributes[j])
                    super_keys.append(combo.copy())
        return super_keys

# Example: Student relation
student_rel = Relation(
    "Student",
    ["SID", "Name", "Email", "Phone"],
    [(1, "John", "john@email.com", "123"),
     (2, "Jane", "jane@email.com", "456")]
)
print(f"Degree: {student_rel.get_degree()}")  # 4
print(f"Cardinality: {student_rel.get_cardinality()}")  # 2

#include <stdio.h>
#include <stdbool.h>

typedef struct {
    int tupleID;
    char name[50];
    int age;
    char email[50];
} Student;

// Check if primary key value is unique
bool isPrimaryKeyUnique(Student students[], int count, int newID) {
    for (int i = 0; i < count; i++) {
        if (students[i].tupleID == newID) {
            return false;  // Duplicate primary key
        }
    }
    return true;
}

// Check referential integrity for foreign key
bool validateForeignKey(int deptIDs[], int deptCount, int foreignDeptID) {
    for (int i = 0; i < deptCount; i++) {
        if (deptIDs[i] == foreignDeptID) {
            return true;  // Valid reference
        }
    }
    return false;  // No matching primary key
}

int main() {
    Student students[] = {{1, "John", 20, "john@email.com"},
                          {2, "Jane", 21, "jane@email.com"}};
    int count = 2;

    // Validate new student with ID 1 (duplicate PK)
    printf("PK Unique Check: %s\n", 
           isPrimaryKeyUnique(students, count, 1) ? "PASS" : "FAIL");

    // Validate foreign key reference
    int deptIDs[] = {10, 20, 30};
    printf("FK Valid Check: %s\n", 
           validateForeignKey(deptIDs, 3, 25) ? "PASS" : "FAIL");

    return 0;
}
